class Solution:
    def maxSumTwoNoOverlap(self, nums, firstLen, secondLen):
        # Brute force: try every placement of both windows in both orders.
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + nums[i]
        def w(i, L):
            return pre[i + L] - pre[i]
        best = 0
        for i in range(0, n - firstLen + 1):
            for j in range(0, n - secondLen + 1):
                if i + firstLen <= j or j + secondLen <= i:
                    best = max(best, w(i, firstLen) + w(j, secondLen))
        return best

