class Solution:
    def maxSumTwoNoOverlap(self, nums, firstLen, secondLen):
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + nums[i]
        def helper(L1, L2):
            best = 0
            bestL1 = 0
            for j in range(L1 + L2, n + 1):
                bestL1 = max(bestL1, pre[j - L2] - pre[j - L2 - L1])
                cur = bestL1 + (pre[j] - pre[j - L2])
                best = max(best, cur)
            return best
        return max(helper(firstLen, secondLen), helper(secondLen, firstLen))

